"""
Parameterized generator for GH508_prisma_29287.

Source PR:    https://github.com/prisma/prisma/pull/29287
Source Issue: N/A

Seed varies: renames 'accept' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH508_prisma_29287'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH508_prisma_29287'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('accept', 'accept' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH508_prisma_29287',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'prisma/prisma',
                "pr_number": 29287,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/prisma/prisma/pull/29287",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'packages/adapter-pg/src/__tests__/pg.test.ts': "import { getLogs } from '@prisma/debug'\nimport pg, { DatabaseError } from 'pg'\nimport { describe, expect, it, vi } from 'vitest'\n\nimport { PrismaPgAdapterFactory } from '../pg'\n\ndescribe('PrismaPgAdapterFactory', () => {\n  it('should subscribe to pool error events', async () => {\n    const config: pg.PoolConfig = { user: 'test', password: 'test', database: 'test', port: 5432, host: 'localhost' }\n    const factory = new PrismaPgAdapterFactory(config)\n    const adapter = await factory.connect()\n\n    const shutdownError = new DatabaseError('terminating connection due to administrator command', 116, 'error')\n    shutdownError.severity = 'FATAL'\n    shutdownError.code = '57P01'\n    shutdownError.routine = 'ProcessInterrupts'\n    shutdownError.line = '3197'\n    shutdownError.file = 'postgres.c'\n\n    adapter['client'].emit('error', shutdownError)\n    await adapter.dispose()\n    const debug = getLogs()\n    expect(debug).toContain('terminating connection due to administrator command')\n  })\n\n  it('should call onPoolError when supplied', async () => {\n    const config: pg.PoolConfig = { user: 'test', password: 'test', database: 'test', port: 5432, host: 'localhost' }\n    const onPoolError = vi.fn()\n    const factory = new PrismaPgAdapterFactory(config, { onPoolError })\n    const adapter = await factory.connect()\n    const error = new Error('Pool error')\n    adapter['client'].emit('error', error)\n    expect(onPoolError).toHaveBeenCalledWith(error)\n    await adapter.dispose()\n  })\n\n  it('should add and remove error event listener when using an external Pool', async () => {\n    const pool = new pg.Pool({ user: 'test', password: 'test', database: 'test', port: 5432, host: 'localhost' })\n    pool.on('error', () => {})\n    const factory = new PrismaPgAdapterFactory(pool)\n    const adapter = await factory.connect()\n    expect(adapter).toBeDefined()\n    expect(adapter.adapterName).toBeDefined()\n    expect(pool.listenerCount('error')).toEqual(2)\n    await adapter.dispose()\n    expect(pool.listenerCount('error')).toEqual(1)\n    await pool.end()\n  })\n\n  it('should remove connection error listener after transaction commit', async () => {\n    const config: pg.PoolConfig = { user: 'test', password: 'test', database: 'test', port: 5432, host: 'localhost' }\n    const factory = new PrismaPgAdapterFactory(config)\n    const adapter = await factory.connect()\n\n    const mockConnection = {\n      on: vi.fn(),\n      removeListener: vi.fn(),\n      query: vi.fn().mockResolvedValue({ rows: [], rowCount: 0 }),\n      release: vi.fn(),\n      listenerCount: vi.fn().mockReturnValue(1),\n    }\n\n    adapter['client'].connect = vi.fn().mockResolvedValue(mockConnection)\n\n    const transaction = await adapter.startTransaction()\n    expect(mockConnection.listenerCount('error')).toEqual(1)\n\n    mockConnection.listenerCount.mockReturnValue(0)\n    await transaction.commit()\n    expect(mockConnection.removeListener).toHaveBeenCalledWith('error', expect.any(Function))\n    expect(mockConnection.listenerCount('error')).toEqual(0)\n\n    await adapter.dispose()\n  })\n\n  it('should remove connection error listener after transaction rollback', async () => {\n    const config: pg.PoolConfig = { user: 'test', password: 'test', database: 'test', port: 5432, host: 'localhost' }\n    const factory = new PrismaPgAdapterFactory(config)\n    const adapter = await factory.connect()\n\n    const mockConnection = {\n      on: vi.fn(),\n      removeListener: vi.fn(),\n      query: vi.fn().mockResolvedValue({ rows: [], rowCount: 0 }),\n      release: vi.fn(),\n      listenerCount: vi.fn().mockReturnValue(1),\n    }\n\n    adapter['client'].connect = vi.fn().mockResolvedValue(mockConnection)\n\n    const transaction = await adapter.startTransaction()\n    expect(mockConnection.listenerCount('error')).toEqual(1)\n\n    mockConnection.listenerCount.mockReturnValue(0)\n    await transaction.rollback()\n    expect(mockConnection.removeListener).toHaveBeenCalledWith('error', expect.any(Function))\n    expect(mockConnection.listenerCount('error')).toEqual(0)\n\n    await adapter.dispose()\n  })\n})\n",
            'packages/adapter-pg/src/pg.ts': '/* eslint-disable @typescript-eslint/require-await */\n\nimport type {\n  ColumnType,\n  ConnectionInfo,\n  IsolationLevel,\n  SqlDriverAdapter,\n  SqlMigrationAwareDriverAdapterFactory,\n  SqlQuery,\n  SqlQueryable,\n  SqlResultSet,\n  Transaction,\n  TransactionOptions,\n} from \'@prisma/driver-adapter-utils\'\nimport { Debug, DriverAdapterError } from \'@prisma/driver-adapter-utils\'\n// @ts-ignore: this is used to avoid the `Module \'"<path>/node_modules/@types/pg/index"\' has no default export.` error.\nimport pg from \'pg\'\n\nimport { name as packageName } from \'../package.json\'\nimport { FIRST_NORMAL_OBJECT_ID } from \'./constants\'\nimport { customParsers, fieldToColumnType, mapArg, UnsupportedNativeDataType } from \'./conversion\'\nimport { convertDriverError } from \'./errors\'\n\nconst types = pg.types\n\nconst debug = Debug(\'prisma:driver-adapter:pg\')\n\ntype StdClient = pg.Pool\ntype TransactionClient = pg.PoolClient\n\nclass PgQueryable<ClientT extends StdClient | TransactionClient> implements SqlQueryable {\n  readonly provider = \'postgres\'\n  readonly adapterName = packageName\n\n  constructor(\n    protected readonly client: ClientT,\n    protected readonly pgOptions?: PrismaPgOptions,\n  ) {}\n\n  /**\n   * Execute a query given as SQL, interpolating the given parameters.\n   */\n  async queryRaw(query: SqlQuery): Promise<SqlResultSet> {\n    const tag = \'[js::query_raw]\'\n    debug(`${tag} %O`, query)\n\n    const { fields, rows } = await this.performIO(query)\n\n    const columnNames = fields.map((field) => field.name)\n    let columnTypes: ColumnType[] = []\n\n    try {\n      columnTypes = fields.map((field) => fieldToColumnType(field.dataTypeID))\n    } catch (e) {\n      if (e instanceof UnsupportedNativeDataType) {\n        throw new DriverAdapterError({\n          kind: \'UnsupportedNativeDataType\',\n          type: e.type,\n        })\n      }\n      throw e\n    }\n\n    const udtParser = this.pgOptions?.userDefinedTypeParser\n    if (udtParser) {\n      for (let i = 0; i < fields.length; i++) {\n        const field = fields[i]\n        if (field.dataTypeID >= FIRST_NORMAL_OBJECT_ID && !Object.hasOwn(customParsers, field.dataTypeID)) {\n          for (let j = 0; j < rows.length; j++) {\n            rows[j][i] = await udtParser(field.dataTypeID, rows[j][i], this)\n          }\n        }\n      }\n    }\n\n    return {\n      columnNames,\n      columnTypes,\n      rows,\n    }\n  }\n\n  /**\n   * Execute a query given as SQL, interpolating the given parameters and\n   * returning the number of affected rows.\n   * Note: Queryable expects a u64, but napi.rs only supports u32.\n   */\n  async executeRaw(query: SqlQuery): Promise<number> {\n    const tag = \'[js::execute_raw]\'\n    debug(`${tag} %O`, query)\n\n    // Note: `rowsAffected` can sometimes be null (e.g., when executing `"BEGIN"`)\n    return (await this.performIO(query)).rowCount ?? 0\n  }\n\n  /**\n   * Run a query against the database, returning the result set.\n   * Should the query fail due to a connection error, the connection is\n   * marked as unhealthy.\n   */\n  private async performIO(query: SqlQuery): Promise<pg.QueryArrayResult<any>> {\n    const { sql, args } = query\n    const values = args.map((arg, i) => mapArg(arg, query.argTypes[i]))\n\n    try {\n      const result = await this.client.query(\n        {\n          text: sql,\n          values,\n          rowMode: \'array\',\n          types: {\n            // This is the error expected:\n            // No overload matches this call.\n            // The last overload gave the following error.\n            // Type \'(oid: number, format?: any) => (json: string) => unknown\' is not assignable to type \'{ <T>(oid: number): TypeParser<string, string | T>; <T>(oid: number, format: "text"): TypeParser<string, string | T>; <T>(oid: number, format: "binary"): TypeParser<...>; }\'.\n            //   Type \'(json: string) => unknown\' is not assignable to type \'TypeParser<Buffer, any>\'.\n            //     Types of parameters \'json\' and \'value\' are incompatible.\n            //       Type \'Buffer\' is not assignable to type \'string\'.ts(2769)\n            //\n            // Because pg-types types expect us to handle both binary and text protocol versions,\n            // where as far we can see, pg will ever pass only text version.\n            //\n            // @ts-expect-error\n            getTypeParser: (oid: number, format?) => {\n              if (format === \'text\' && customParsers[oid]) {\n                return customParsers[oid]\n              }\n\n              return types.getTypeParser(oid, format)\n            },\n          },\n        },\n        values,\n      )\n\n      return result\n    } catch (e) {\n      this.onError(e)\n    }\n  }\n\n  protected onError(error: unknown): never {\n    debug(\'Error in performIO: %O\', error)\n    throw new DriverAdapterError(convertDriverError(error))\n  }\n}\n\nclass PgTransaction extends PgQueryable<TransactionClient> implements Transaction {\n  constructor(\n    client: pg.PoolClient,\n    readonly options: TransactionOptions,\n    readonly pgOptions?: PrismaPgOptions,\n    readonly cleanup?: () => void,\n  ) {\n    super(client, pgOptions)\n  }\n\n  async commit(): Promise<void> {\n    debug(`[js::commit]`)\n\n    this.cleanup?.()\n    this.client.release()\n  }\n\n  async rollback(): Promise<void> {\n    debug(`[js::rollback]`)\n\n    this.cleanup?.()\n    this.client.release()\n  }\n\n  async createSavepoint(name: string): Promise<void> {\n    await this.executeRaw({ sql: `SAVEPOINT ${name}`, args: [], argTypes: [] })\n  }\n\n  async rollbackToSavepoint(name: string): Promise<void> {\n    await this.executeRaw({ sql: `ROLLBACK TO SAVEPOINT ${name}`, args: [], argTypes: [] })\n  }\n\n  async releaseSavepoint(name: string): Promise<void> {\n    await this.executeRaw({ sql: `RELEASE SAVEPOINT ${name}`, args: [], argTypes: [] })\n  }\n}\n\nexport type PrismaPgOptions = {\n  schema?: string\n  disposeExternalPool?: boolean\n  onPoolError?: (err: Error) => void\n  onConnectionError?: (err: Error) => void\n  userDefinedTypeParser?: UserDefinedTypeParser\n}\n\nexport type UserDefinedTypeParser = (oid: number, value: unknown, adapter: SqlQueryable) => Promise<unknown>\n\nexport class PrismaPgAdapter extends PgQueryable<StdClient> implements SqlDriverAdapter {\n  constructor(\n    client: StdClient,\n    protected readonly pgOptions?: PrismaPgOptions,\n    private readonly release?: () => Promise<void>,\n  ) {\n    super(client)\n  }\n\n  async startTransaction(isolationLevel?: IsolationLevel): Promise<Transaction> {\n    const options: TransactionOptions = {\n      usePhantomQuery: false,\n    }\n\n    const tag = \'[js::startTransaction]\'\n    debug(\'%s options: %O\', tag, options)\n\n    const conn = await this.client.connect().catch((error) => this.onError(error))\n    const onError = (err: Error) => {\n      debug(`Error from pool connection: ${err.message} %O`, err)\n      this.pgOptions?.onConnectionError?.(err)\n    }\n    conn.on(\'error\', onError)\n\n    const cleanup = () => {\n      conn.removeListener(\'error\', onError)\n    }\n\n    try {\n      const tx = new PgTransaction(conn, options, this.pgOptions, cleanup)\n      await tx.executeRaw({ sql: \'BEGIN\', args: [], argTypes: [] })\n      if (isolationLevel) {\n        await tx.executeRaw({\n          sql: `SET TRANSACTION ISOLATION LEVEL ${isolationLevel}`,\n          args: [],\n          argTypes: [],\n        })\n      }\n      return tx\n    } catch (error) {\n      cleanup()\n      conn.release(error)\n      this.onError(error)\n    }\n  }\n\n  async executeScript(script: string): Promise<void> {\n    // FIXME: there\'s no guarantee that the semicolon is between statements\n    // and not inside one.\n    const statements = script\n      .split(\';\')\n      .map((stmt) => stmt.trim())\n      .filter((stmt) => stmt.length > 0)\n\n    for (const stmt of statements) {\n      try {\n        await this.client.query(stmt)\n      } catch (error) {\n        this.onError(error)\n      }\n    }\n  }\n\n  getConnectionInfo(): ConnectionInfo {\n    return {\n      schemaName: this.pgOptions?.schema,\n      supportsRelationJoins: true,\n    }\n  }\n\n  async dispose(): Promise<void> {\n    return this.release?.()\n  }\n\n  underlyingDriver(): pg.Pool {\n    return this.client\n  }\n}\n\nexport class PrismaPgAdapterFactory implements SqlMigrationAwareDriverAdapterFactory {\n  readonly provider = \'postgres\'\n  readonly adapterName = packageName\n  private readonly config: pg.PoolConfig\n  private externalPool: pg.Pool | null\n\n  constructor(\n    poolOrConfig: pg.Pool | pg.PoolConfig,\n    private readonly options?: PrismaPgOptions,\n  ) {\n    if (poolOrConfig instanceof pg.Pool) {\n      this.externalPool = poolOrConfig\n      this.config = poolOrConfig.options\n    } else {\n      this.externalPool = null\n      this.config = poolOrConfig\n    }\n  }\n\n  async connect(): Promise<PrismaPgAdapter> {\n    const client = this.externalPool ?? new pg.Pool(this.config)\n\n    const onIdleClientError = (err: Error) => {\n      debug(`Error from idle pool client: ${err.message} %O`, err)\n      this.options?.onPoolError?.(err)\n    }\n    client.on(\'error\', onIdleClientError)\n\n    return new PrismaPgAdapter(client, this.options, async () => {\n      if (this.externalPool) {\n        if (this.options?.disposeExternalPool) {\n          await this.externalPool.end()\n          this.externalPool = null\n        } else {\n          this.externalPool.removeListener(\'error\', onIdleClientError)\n        }\n      } else {\n        await client.end()\n      }\n    })\n  }\n\n  async connectToShadowDb(): Promise<PrismaPgAdapter> {\n    const conn = await this.connect()\n    const database = `prisma_migrate_shadow_db_${globalThis.crypto.randomUUID()}`\n    await conn.executeScript(`CREATE DATABASE "${database}"`)\n\n    const client = new pg.Pool({ ...this.config, database })\n    return new PrismaPgAdapter(client, undefined, async () => {\n      await conn.executeScript(`DROP DATABASE "${database}"`)\n      await client.end()\n    })\n  }\n}\n',
        }
